import{_ as n,o as h,c as i,a0 as o}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Bảo trì","description":"","frontmatter":{"title":"Bảo trì"},"headers":[],"relativePath":"maintenance.md","filePath":"maintenance.md"}'),r={name:"maintenance.md"};function a(c,t,g,e,s,l){return h(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="bao-tri" tabindex="-1">Bảo trì <a class="header-anchor" href="#bao-tri" aria-label="Permalink to &quot;Bảo trì&quot;">​</a></h1><p>Mô-đun <strong>Bảo trì (Maintenance)</strong> trong ABNERP giúp doanh nghiệp quản lý các hoạt động bảo trì tài sản, thiết bị và máy móc một cách có hệ thống. Việc lập kế hoạch và theo dõi bảo trì đúng hạn giúp kéo dài tuổi thọ tài sản và giảm thiểu thời gian ngừng hoạt động ngoài kế hoạch.</p><h2 id="lich-bao-tri" tabindex="-1">Lịch bảo trì <a class="header-anchor" href="#lich-bao-tri" aria-label="Permalink to &quot;Lịch bảo trì&quot;">​</a></h2><p><strong>Lịch bảo trì (Maintenance Schedule)</strong> cho phép lập kế hoạch bảo trì theo lịch trình định kỳ cho từng tài sản hoặc thiết bị. Khi tạo lịch bảo trì, người dùng có thể thiết lập:</p><ul><li><strong>Tài sản/thiết bị</strong>: đối tượng cần bảo trì</li><li><strong>Loại bảo trì</strong>: bảo trì phòng ngừa, bảo trì định kỳ, sửa chữa</li><li><strong>Tần suất</strong>: hàng ngày, hàng tuần, hàng tháng, hàng quý, hàng năm</li><li><strong>Ngày bắt đầu</strong>: ngày bắt đầu thực hiện lịch bảo trì</li><li><strong>Ngày kết thúc</strong>: ngày kết thúc (nếu có)</li><li><strong>Phân công</strong>: nhân viên hoặc nhóm bảo trì phụ trách</li></ul><p>Khi đến hạn, hệ thống tự động tạo <strong>Phiếu bảo trì (Maintenance Visit)</strong> tương ứng.</p><h2 id="phieu-bao-tri" tabindex="-1">Phiếu bảo trì <a class="header-anchor" href="#phieu-bao-tri" aria-label="Permalink to &quot;Phiếu bảo trì&quot;">​</a></h2><p><strong>Phiếu bảo trì (Maintenance Visit)</strong> ghi nhận thông tin chi tiết của mỗi lần thực hiện bảo trì. Mỗi phiếu bảo trì bao gồm:</p><ul><li><strong>Thông tin tài sản</strong>: tên, mã hiệu, vị trí</li><li><strong>Ngày thực hiện</strong>: thời gian bảo trì</li><li><strong>Nhân viên thực hiện</strong>: kỹ thuật viên hoặc đội bảo trì</li><li><strong>Nội dung công việc</strong>: các hạng mục đã thực hiện</li><li><strong>Linh kiện/vật tư thay thế</strong>: danh sách vật tư sử dụng và chi phí</li><li><strong>Kết quả</strong>: thành công, cần theo dõi thêm, hoặc cần sửa chữa lớn</li><li><strong>Chi phí</strong>: tổng chi phí bảo trì (nhân công + vật tư)</li></ul><p>Phiếu bảo trì có thể được tạo thủ công hoặc tự động từ lịch bảo trì đã thiết lập. Các phiếu bảo trì tạo ra từ lịch sẽ tự động điền các thông tin từ lịch bảo trì mẹ, tiết kiệm thời gian cho người vận hành.</p><h3 id="theo-doi-va-bao-cao" tabindex="-1">Theo dõi và báo cáo <a class="header-anchor" href="#theo-doi-va-bao-cao" aria-label="Permalink to &quot;Theo dõi và báo cáo&quot;">​</a></h3><p>Mô-đun Bảo trì cung cấp các báo cáo bao gồm lịch sử bảo trì của từng tài sản, tổng chi phí bảo trì theo thời gian và danh sách bảo trì sắp đến hạn — giúp quản lý tài sản hiệu quả và minh bạch.</p>',12)])])}const p=n(r,[["render",a]]);export{u as __pageData,p as default};
